def verify(output: str):
    # Initialize constraint satisfaction tracking
    constraints_satisfied = 0
    total_constraints = 5
    failed_constraints = []

    # Check 1: The string contains exactly 1 occurrence of the substring 2026
    if output.count("2026") == 1:
        constraints_satisfied += 1
    else:
        failed_constraints.append(f"Contains {output.count('2026')} occurrence(s) of '2026' instead of exactly 1")

    # Check 2: The string contains no occurrence of 000
    if "000" not in output:
        constraints_satisfied += 1
    else:
        failed_constraints.append("Contains occurrence of '000'")

    # Check 3: The string must not start with 0
    if output[0] != '0':
        constraints_satisfied += 1
    else:
        failed_constraints.append("Starts with '0'")

    # Check 4: The string must end with an odd digit
    odd_digits = {'1', '3', '5', '7', '9'}
    if output[-1] in odd_digits:
        constraints_satisfied += 1
    else:
        failed_constraints.append(f"Ends with '{output[-1]}' (not an odd digit)")

    # Check 5: The total number of even digits is exactly 10
    even_digits = {'0', '2', '4', '6', '8'}
    even_count = sum(1 for digit in output if digit in even_digits)
    if even_count == 10:
        constraints_satisfied += 1
    else:
        failed_constraints.append(f"Contains {even_count} even digit(s) instead of exactly 10")

    # Additional checks (implicit constraints from the problem)
    # - Length must be exactly 20
    if len(output) != 20:
        # This is not counted as a constraint, but we'll note it in the message if relevant
        # However, per problem, candidate output follows output format, so we assume 20 digits
        pass

    # Calculate score
    score = constraints_satisfied / total_constraints

    # Determine validity
    is_valid = constraints_satisfied == total_constraints

    # Generate message
    if is_valid:
        message = "All constraints satisfied"
    else:
        message = "Constraints failed: " + "; ".join(failed_constraints)

    return (is_valid, score, message)
